mapper.sql:
select distinct x.did from (
    select cast(upd.dept_id as unsigned) as did
    from sb_user_permission_dept upd
    where upd.user_id = #{params.scopeDeptUserId}
      and ifnull(upd.del_flag, '0') = '0'

      and upd.customer_id = #{params.scopeDeptCustomerId}

    union
    select ud.department_id as did
    from sys_user_department ud
    where ud.user_id = #{params.scopeDeptUserId}
      and (ud.status = 0 or ud.status = '0' or ud.status is null)
) x
where x.did is not null

mapper.select:



     and a.apply_bill_no = #{applyBillNo}
     and a.apply_bill_date = #{applyBillDate}
     and a.warehouse_id = #{warehouseId}
     and a.department_id = #{departmentId}
     and a.user_id = #{userId}
     and a.apply_bill_status = #{applyBillStatus}
     and COALESCE(a.bill_type, 1) = #{billType}

    and a.tenant_id = #{scopedTenantId}
    and (a.del_flag = 0 or a.del_flag is null)

order by
    case when a.apply_bill_status = 2 then 1 else 0 end asc,
    case when a.apply_bill_status = 2 then a.audit_date else null end desc,
    case when a.apply_bill_status = 2 then null else a.create_time end desc,
    a.id desc

mapper.update:
update bas_apply
apply_bill_no = #{applyBillNo}, apply_bill_date = #{applyBillDate}, warehouse_id = null, warehouse_id = #{warehouseId}, department_id = #{departmentId}, user_id = #{userId}, apply_bill_status = #{applyBillStatus}, bill_type = #{billType}, del_flag = #{delFlag}, create_by = #{createBy}, create_time = #{createTime}, update_by = #{updateBy}, update_time = #{updateTime}, remark = #{remark}, audit_by = #{auditBy}, audit_date = #{auditDate}, reject_reason = #{rejectReason}, tenant_id = #{tenantId},
where id = #{id} and tenant_id = #{scopedTenantId}

mapper.select:

select coalesce(sum(e.qty), 0)
from bas_apply a
inner join bas_apply_entry e on e.paren_id = a.id and e.tenant_id = #{scopedTenantId} and (e.del_flag is null or e.del_flag != 1)
where a.tenant_id = #{scopedTenantId}
  and (a.del_flag = 0 or a.del_flag is null)
 and a.apply_bill_date = #{applyBillDate}
 and a.apply_bill_status = #{applyBillStatus}
 and COALESCE(a.bill_type, 1) = #{billType}
